import { Injectable } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { Promotion, PromotionStats, PromotionStatus } from '../../models';

@Injectable({ providedIn: 'root' })
export class PromotionService extends BaseService<Promotion> {

  // ─── BaseService richiede solo questo ──────────────────────
  protected override getTableName(): string {
    return 'promotions';
  }

  // ─── Filtri in-memory (nessuna chiamata extra al DB) ────────

  /** Promozioni per status, calcolate sul dataSubject già caricato */
  getByStatus(status: PromotionStatus): Promotion[] {
    return this.dataSubject.value.filter(p => p.status === status);
  }

  /** Promozioni attive e temporalmente valide adesso */
  getActiveNow(): Promotion[] {
    const now = new Date();
    return this.dataSubject.value.filter(p =>
      p.status === 'active' &&
      new Date(p.valid_from) <= now &&
      (!p.valid_until || new Date(p.valid_until) >= now)
    );
  }

  /** Contatori per i filtri tab (evita 5 query separate) */
  getStatusCounts(): Record<PromotionStatus | 'all', number> {
    const all = this.dataSubject.value;
    return {
      all:      all.length,
      draft:    all.filter(p => p.status === 'draft').length,
      active:   all.filter(p => p.status === 'active').length,
      paused:   all.filter(p => p.status === 'paused').length,
      expired:  all.filter(p => p.status === 'expired').length,
      archived: all.filter(p => p.status === 'archived').length,
    };
  }

  // ─── Azioni rapide (usano update() del BaseService) ─────────

  /** Cambia stato di una promozione */
  async toggleStatus(id: string, newStatus: PromotionStatus): Promise<boolean> {
    return this.update(id, { status: newStatus });
  }

  /** Attiva → Sospendi e viceversa in un click */
  async toggleActiveState(promotion: Promotion): Promise<boolean> {
    const newStatus: PromotionStatus = promotion.status === 'active' ? 'paused' : 'active';
    return this.toggleStatus(promotion.id, newStatus);
  }

  /** Clona una promozione esistente come bozza */
  async duplicate(promotion: Promotion): Promise<Promotion | null> {
    const copy: Partial<Promotion> = {
      name:                 `${promotion.name} (copia)`,
      description:          promotion.description,
      internal_note:        promotion.internal_note,
      type:                 promotion.type,
      target:               promotion.target,
      discount_value:       promotion.discount_value,
      max_discount_amount:  promotion.max_discount_amount,
      valid_from:           new Date().toISOString().split('T')[0],
      valid_until:          null,
      max_uses_total:       promotion.max_uses_total,
      max_uses_per_customer: promotion.max_uses_per_customer,
      min_order_amount:     promotion.min_order_amount,
      priority:             promotion.priority,
      stacking:             promotion.stacking,
      status:               'draft',      // sempre bozza
      is_public:            promotion.is_public,
    };
    return this.create(copy);
  }

  // ─── Analytics (query su promotion_usages) ──────────────────

  /** Statistiche di utilizzo per una singola promozione */
  async getStats(promotionId: string): Promise<PromotionStats | null> {
    try {
      const { data, error } = await this.run(
        this.supabaseService.getSupabaseClient()
          .from('promotion_usages')
          .select('discount_applied, order_total_before, order_total_after')
          .eq('promotion_id', promotionId)
      );

      if (error || !data) return null;

      const uses = data as any[];
      const totalDiscount = uses.reduce((sum, u) => sum + (u.discount_applied ?? 0), 0);
      const avgOrderValue = uses.length > 0
        ? uses.reduce((sum, u) => sum + (u.order_total_before ?? 0), 0) / uses.length
        : 0;

      return {
        promotion_id:        promotionId,
        total_uses:          uses.length,
        total_discount_given: totalDiscount,
        avg_order_value:     avgOrderValue,
      };
    } catch {
      return null;
    }
  }

  // ─── Utility ────────────────────────────────────────────────

  /** Formatta il valore dello sconto in modo leggibile */
  formatDiscountValue(promotion: Promotion): string {
    switch (promotion.type) {
      case 'percentage':
        return `${promotion.discount_value}%`;
      case 'fixed_amount':
        return `-€${promotion.discount_value.toFixed(2)}`;
      case 'happy_hour':
        return `${promotion.discount_value}% (Happy Hour)`;
      case 'buy_x_get_y':
        return `Bundle`;
      case 'free_item':
        return `Omaggio`;
      default:
        return `${promotion.discount_value}`;
    }
  }

  /** Restituisce true se la promozione è scaduta per data o esaurimento */
  isExpired(promotion: Promotion): boolean {
    if (promotion.valid_until && new Date(promotion.valid_until) < new Date()) return true;
    if (promotion.max_uses_total && promotion.current_uses >= promotion.max_uses_total) return true;
    return false;
  }
}