import { Component, OnInit, OnDestroy, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { filter, Subject, takeUntil } from 'rxjs';
import { CreatePromotionDto, DISCOUNT_TARGET_LABELS, DiscountTarget, getDefaultPromotion, Promotion, PROMOTION_STATUS_LABELS, PROMOTION_TYPE_LABELS, PromotionStatus, PromotionType, STACKING_LABELS, StackingPolicy } from '../../models';
import { PromotionService } from '../../services/Marketing-Management/promotion.service';
import { LucideAngularModule } from 'lucide-angular';
import { RestaurantFollowerService } from '../../services/restaurant-follower.service';
import { AuthService } from '../../services/Base/auth.service';
import { PromotionNotificationService, SendErrorCode } from '../../services/promotion-notification.service';
import { SupabaseService } from '../../services/Base/supabase.service';


type FilterStatus = PromotionStatus | 'all';

@Component({
  selector: 'app-marketing-management',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './marketing-management.html',
  styleUrls: ['./marketing-management.css'],
})
export class MarketingManagement implements OnInit, OnDestroy {

  private promotionService = inject(PromotionService);
  private destroy$ = new Subject<void>();
  private followerService = inject(RestaurantFollowerService);
  private authService = inject(AuthService);
  private promoNotifService = inject(PromotionNotificationService);
  private supabaseService = inject(SupabaseService);

  // ─── State ──────────────────────────────────────────────────
  promotions: Promotion[] = [];
  loading = false;
  error: string | null = null;

  // Follower
  followerCount = 0;
  followers: { user_id: string; followed_at: string; users?: { first_name: string; last_name: string; email: string } }[] = [];
  isLoadingFollowers = false;

  // PROMOZIONI INVIO
  notifiedPromotions = new Set<string>();
  sendingNotification: string | null = null; // id della promo in invio
  daysUntilNext = 0;

  activeFilter = signal<FilterStatus>('all');
  statusCounts: Record<FilterStatus, number> = {
    all: 0, draft: 0, active: 0, paused: 0, expired: 0, archived: 0,
  };

  // ─── Modal State ─────────────────────────────────────────────
  showFormModal    = false;
  showDeleteModal  = false;
  showStatsModal   = false;
  isSaving         = false;

  selectedPromotion: Promotion | null = null;
  formData: CreatePromotionDto = getDefaultPromotion();

  // Stats
  selectedStats: { total_uses: number; total_discount_given: number; avg_order_value: number } | null = null;
  loadingStats = false;

  // ─── Lookup tables per il template ──────────────────────────
  readonly typeLabels    = PROMOTION_TYPE_LABELS;
  readonly statusLabels  = PROMOTION_STATUS_LABELS;
  readonly targetLabels  = DISCOUNT_TARGET_LABELS;
  readonly stackingLabels = STACKING_LABELS;

  readonly promotionTypes: PromotionType[]   = ['percentage', 'fixed_amount', 'happy_hour', 'buy_x_get_y', 'free_item'];
  readonly discountTargets: DiscountTarget[] = ['order', 'category', 'product', 'delivery'];
  readonly stackingPolicies: StackingPolicy[] = ['exclusive', 'cumulative', 'best_deal'];

  readonly filterTabs: { key: FilterStatus; label: string }[] = [
    { key: 'all',      label: 'Tutte' },
    { key: 'active',   label: 'Attive' },
    { key: 'draft',    label: 'Bozze' },
    { key: 'paused',   label: 'Sospese' },
    { key: 'expired',  label: 'Scadute' },
    { key: 'archived', label: 'Archivio' },
  ];

  // ─── Computed: promozioni filtrate ──────────────────────────
  get filteredPromotions(): Promotion[] {
    const filter = this.activeFilter();
    if (filter === 'all') return this.promotions;
    return this.promotions.filter(p => p.status === filter);
  }

  // ─── Lifecycle ──────────────────────────────────────────────
ngOnInit(): void {
  this.promotionService.data$
    .pipe(takeUntil(this.destroy$))
    .subscribe(promotions => {
      this.promotions   = promotions;
      this.statusCounts = this.promotionService.getStatusCounts();
      // Aggiorna stati notifica ogni volta che cambiano le promozioni
      this.loadNotificationStates();
    });

  this.promotionService.loading$
    .pipe(takeUntil(this.destroy$))
    .subscribe(loading => this.loading = loading);

  this.promotionService.error$
    .pipe(takeUntil(this.destroy$))
    .subscribe(error => this.error = error);

  this.promotionService.loadData();

  this.authService.activeRestaurantId$
    .pipe(
      takeUntil(this.destroy$),
      filter(id => !!id)
    )
    .subscribe(restaurantId => {
      this.loadFollowers(restaurantId!);
    });
}

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  // ─── Navigazione Tab ────────────────────────────────────────
  setFilter(status: FilterStatus): void {
    this.activeFilter.set(status);
  }

  // ─── Form Modal: Crea ────────────────────────────────────────
  openCreateModal(): void {
    this.selectedPromotion = null;
    this.formData          = getDefaultPromotion();
    this.showFormModal     = true;
  }

  // ─── Form Modal: Modifica ────────────────────────────────────
  openEditModal(promotion: Promotion): void {
    this.selectedPromotion = promotion;
    // Copia tutti i campi editabili nel form
    this.formData = {
      name:                  promotion.name,
      description:           promotion.description ?? null,
      internal_note:         promotion.internal_note ?? null,
      image_url:             promotion.image_url ?? null,
      type:                  promotion.type,
      target:                promotion.target,
      discount_value:        promotion.discount_value,
      max_discount_amount:   promotion.max_discount_amount ?? null,
      valid_from:            promotion.valid_from.split('T')[0],
      valid_until:           promotion.valid_until ? promotion.valid_until.split('T')[0] : null,
      max_uses_total:        promotion.max_uses_total ?? null,
      max_uses_per_customer: promotion.max_uses_per_customer ?? null,
      min_order_amount:      promotion.min_order_amount,
      priority:              promotion.priority,
      stacking:              promotion.stacking,
      status:                promotion.status,
      is_public:             promotion.is_public,
    };
    this.showFormModal = true;
  }

  closeFormModal(): void {
    this.showFormModal = false;
    this.selectedPromotion = null;
  }

  // ─── Salva (Crea o Aggiorna) ─────────────────────────────────
  async savePromotion(): Promise<void> {
    if (!this.formData.name?.trim()) return;
    this.isSaving = true;

    try {
      if (this.selectedPromotion) {
        await this.promotionService.update(this.selectedPromotion.id, this.formData as any);
      } else {
        await this.promotionService.create(this.formData as any);
      }
      this.closeFormModal();
    } finally {
      this.isSaving = false;
    }
  }

  // ─── Elimina ──────────────────────────────────────────────────
  openDeleteModal(promotion: Promotion): void {
    this.selectedPromotion = promotion;
    this.showDeleteModal   = true;
  }

  closeDeleteModal(): void {
    this.showDeleteModal   = false;
    this.selectedPromotion = null;
  }

  async confirmDelete(): Promise<void> {
    if (!this.selectedPromotion) return;
    this.isSaving = true;
    try {
      await this.promotionService.delete(this.selectedPromotion.id);
      this.closeDeleteModal();
    } finally {
      this.isSaving = false;
    }
  }

  // ─── Azioni rapide ────────────────────────────────────────────
  async toggleStatus(promotion: Promotion): Promise<void> {
    await this.promotionService.toggleActiveState(promotion);
  }

  async duplicate(promotion: Promotion): Promise<void> {
    await this.promotionService.duplicate(promotion);
  }

  async publishDraft(promotion: Promotion): Promise<void> {
    await this.promotionService.toggleStatus(promotion.id, 'active');
  }

  // ─── Stats Modal ─────────────────────────────────────────────
  async openStatsModal(promotion: Promotion): Promise<void> {
    this.selectedPromotion = promotion;
    this.selectedStats     = null;
    this.showStatsModal    = true;
    this.loadingStats      = true;

    try {
      this.selectedStats = await this.promotionService.getStats(promotion.id);
    } finally {
      this.loadingStats = false;
    }
  }

  closeStatsModal(): void {
    this.showStatsModal    = false;
    this.selectedPromotion = null;
    this.selectedStats     = null;
  }

  // ─── Utility per il template ─────────────────────────────────

  formatDiscount(p: Promotion): string {
    return this.promotionService.formatDiscountValue(p);
  }

  isExpired(p: Promotion): boolean {
    return this.promotionService.isExpired(p);
  }

  formatDate(dateStr: string | null | undefined): string {
    if (!dateStr) return '∞';
    return new Date(dateStr).toLocaleDateString('it-IT', { day: '2-digit', month: 'short', year: 'numeric' });
  }

  /** Usata nel template per il campo discount_value:
   *  mostra il simbolo corretto a seconda del tipo selezionato */
  get discountSuffix(): string {
    return this.formData.type === 'percentage' ? '%' : '€';
  }

  /** Mostra il campo max_discount_amount solo se tipo = percentage */
  get showMaxCap(): boolean {
    return this.formData.type === 'percentage';
  }

  /** Determina se una promozione è attivabile (non scaduta, non archived) */
  canToggle(p: Promotion): boolean {
    return p.status !== 'expired' && p.status !== 'archived';
  }

  getUsagePercent(p: Promotion): number {
    if (!p.max_uses_total || p.max_uses_total === 0) return 0;
    return Math.min(100, Math.round((p.current_uses / p.max_uses_total) * 100));
  }

  trackById(_: number, item: Promotion): string {
    return item.id;
  }

  objectKeys(obj: object): string[] {
    return Object.keys(obj);
  }

private async loadFollowers(restaurantId: string) {
  this.isLoadingFollowers = true;
  console.log('🔄 Caricamento follower per ristorante:', restaurantId);
  try {
    const result = await this.followerService.getFollowersForRestaurant(restaurantId);
    console.log('✅ Risultato dal servizio:', result);
    this.followers = result || [];
    this.followerCount = this.followers.length;
    console.log('📊 followers array:', this.followers);
  } catch (error) {
    console.error('❌ Errore nel caricamento follower:', error);
    this.followers = [];
    this.followerCount = 0;
  } finally {
    this.isLoadingFollowers = false;
  }
}

private async loadNotificationStates() {
  const days = await this.promoNotifService.daysUntilNextAllowed();
  this.daysUntilNext = days;

  for (const promo of this.promotions) {
    const notified = await this.promoNotifService.hasBeenNotified(promo.id);
    if (notified) this.notifiedPromotions.add(promo.id);
  }
}

async sendNotification(promo: Promotion) {
  if (this.sendingNotification) return;
  this.sendingNotification = promo.id;

  try {
    // ✅ Controllo contesto e ristorante attivo
    if (!this.authService.isRestaurantUser()) {
      alert('⚠️ Devi essere in modalità ristorante per inviare promozioni.');
      return;
    }

    const restaurantId = this.authService.getCurrentRestaurantId();
    if (!restaurantId) {
      alert('⚠️ Nessun ristorante attivo selezionato.');
      return;
    }

    // ✅ Prendi follower con notifiche attive
    const followers = await this.followerService.getFollowersForRestaurant(restaurantId);
    const pushableFollowers = followers.filter(f => f.users); 
    if (pushableFollowers.length === 0) {
      alert('⚠️ Nessun follower con notifiche push attive.');
      return;
    }

    // ✅ Controllo limite settimanale
    const daysLeft = await this.promoNotifService.daysUntilNextAllowed();
    if (daysLeft > 0) {
      alert(`⚠️ Limite settimanale raggiunto. Riprova tra ${daysLeft} giorni.`);
      return;
    }

    // ✅ Invio notifica
    const result = await this.promoNotifService.sendPromotionPush(promo.id);

    // ✅ Gestione esito
    if (result.success) {
      this.notifiedPromotions.add(promo.id);
      this.daysUntilNext = 7;
      alert(`✅ Notifica inviata a ${result.sent} follower`);
    } else {
      const messages: Record<SendErrorCode, string> = {
        already_sent: 'Notifica già inviata per questa promozione.',
        weekly_limit: `Limite settimanale raggiunto. Riprova tra ${this.daysUntilNext} giorni.`,
        no_recipients: 'Nessun follower con notifiche push attive.',
        unknown: result.message || 'Errore sconosciuto'
      };
      const code: SendErrorCode = (result.errorCode as SendErrorCode) ?? 'unknown';
      alert('⚠️ ' + messages[code]);
    }

  } catch (err) {
    console.error('Errore in sendNotification:', err);
    alert('❌ Errore durante l\'invio della notifica. Controlla console.');
  } finally {
    this.sendingNotification = null;
  }
}

canSendNotification(promo: Promotion): boolean {
  return promo.status === 'active'
    && !this.notifiedPromotions.has(promo.id)
    && this.daysUntilNext === 0
    && this.sendingNotification === null;
}

}